example.code:
# Tool wrapper offloads when its output is large.
def web_search(query: str) -> dict:
    raw = provider.search(query)            # full HTML/JSON response
    if token_count(raw) > 2000:
        path = fs.write(f"search/{slug(query)}.json", raw)
        return {"path": path, "head": raw[:600], "kind": "offloaded"}
    return {"inline": raw, "kind": "inline"}

{
  "name": "read_file",
  "description": "Read a file from agent working memory. Use offset+limit to stream large files in chunks.",
  "input_schema": {
    "type": "object",
    "required": ["path"],
    "properties": {
      "path": {"type": "string"},
      "offset": {"type": "integer", "default": 0},
      "limit": {"type": "integer", "default": 2000}
    }
  }
}

# Server-side copy primitive — content never enters the model.
@tool
def copy_file(src: str, dst: str) -> dict:
    fs.copy(src, dst)
    return {"copied_from": src, "to": dst}
